import { registerMvuSchema } from "https://testingcf.jsdelivr.net/gh/StageDog/tavern_resource/dist/util/mvu_zod.js";
export const Schema = z.object({
    // 时间与进度变量
    世界状态: z.object({
        当前日期: z.string().regex(/^\d{4}-\d{2}-\d{2}$/).describe('格式：YYYY-MM-DD').prefault('2024-10-15'),
        当前星期: z.enum(['星期一', '星期二', '星期三', '星期四', '星期五', '星期六', '星期日']).prefault('星期二'),
        当前时间: z.string().regex(/^\d{2}:\d{2}$/).describe('格式：HH:MM，24小时制').prefault('09:30'),
        季节: z.enum(['春', '夏', '秋', '冬']).prefault('秋'),
        天气: z.string().prefault('阴天有雾'),
        随机种子: z.coerce.number().prefault(7348291)
    }).prefault({}),
    // 主角状态
    主角: z.object({
        姓名: z.string().prefault('悠人'),
        年龄: z.coerce.number().min(0).max(100).prefault(14),
        地点: z.string().prefault('避难所储藏室'),
        目标角色: z.array(z.string()).transform(arr => [...new Set(arr)]).describe('主角选择的目标女角色姓名列表').prefault([])
    }).prefault({}),
    // 女性角色变量 - 动态键名
    目标角色: z.record(z.string().describe('角色ID'), z.object({
        姓名: z.string().prefault(''),
        生理状态: z.enum(['安全日', '危险日', '排卵期', '排卵期临近', '月经期', '未知']).prefault('安全日'),
        情绪状态: z.string().prefault('平静'),
        好感度: z.coerce.number().transform(value => _.clamp(value, 0, 100)).prefault(50),
        性欲: z.coerce.number().transform(value => _.clamp(value, 0, 100)).prefault(0),
        欲望: z.string().prefault('未知'),
        年龄: z.coerce.number().min(0).max(100).prefault(30),
        罩杯: z.string().prefault('未知'),
        身高: z.string().regex(/^\d+cm$/).describe('格式：数字+cm').prefault('160cm'),
        三围: z.string().regex(/^\d+cm-\d+cm-\d+cm$/).describe('格式：胸围-腰围-臀围，单位cm').prefault('80cm-60cm-85cm'),
        职业身份: z.string().prefault('未知'),
        外貌特征: z.object({
            体型: z.string().prefault('普通'),
            发型: z.string().prefault('长发'),
            着装风格: z.string().prefault('随意'),
            标志性特点: z.string().prefault('无')
        }).prefault({}),
        性格: z.array(z.string()).max(5).prefault([]),
        内心想法: z.string().prefault(''),
        着装: z.array(z.string()).prefault([]),
        持有物品: z.record(z.string().describe('物品名'), z.object({
            数量: z.coerce.number().min(1).prefault(1),
            描述: z.string()
        })).prefault({}),
        地点: z.string().prefault('未知'),
        最后更新时间: z.coerce.number().prefault(() => Date.now())
    })).prefault({}),
}).prefault({});
(() => {
    registerMvuSchema(Schema);
})();
